sql:
SELECT COUNT(*) AS successful_cleanses
FROM data_cleansing
WHERE cleansing_result = 'success';

SELECT label
FROM livestock
WHERE is_pure_bred = 1;

SELECT AVG(weight) AS average_weight
FROM livestock
WHERE is_pure_bred = 1;

external_knowledge:
- 'Healthy' refers to the livestock that do not have any illnesses; 
- 'Successfully cleansed' means that the data cleansing process was completed without any errors;
- 'Past 30 days' refers to the time period of one month from the current date.

sql:
SELECT COUNT(livestock_id) AS normalized_count
FROM data_normalizations
WHERE normalization_result = 'success';

SELECT id
FROM livestock
ORDER BY id;
